// Declared at module scope so strict-mode ES module assignment works
let currentMode = 'accurate';   // default: dual verification (ML + Google Safe Browsing)

function initSettings() {
    chrome.storage.local.get('phishingMode', (data) => {
        currentMode = data.phishingMode || 'accurate';
    });
    chrome.storage.onChanged.addListener((changes, namespace) => {
        if (namespace === 'local' && changes.phishingMode) {
            currentMode = changes.phishingMode.newValue;
        }
    });
}

function updateBadge(risk, tabId) {
    let color = '#95a5a6';
    let text = '?';
    if (risk === 'HIGH') {
        color = '#e74c3c';
        text = '!';
    } else if (risk === 'MEDIUM') {
        color = '#f39c12';
        text = '~';
    } else if (risk === 'LOW') {
        color = '#2ecc71';
        text = '✓';
    }
    chrome.action.setBadgeBackgroundColor({ color, tabId });
    chrome.action.setBadgeText({ text, tabId });
}

function clearBadge(tabId) {
    chrome.action.setBadgeText({ text: '', tabId });
}

// ── Google Safe Browsing API check ─────────────────────────────────────────
// Uses the Google Safe Browsing v4 Lookup API. The API key is intentionally
// left as a placeholder — the user should obtain a free key from:
// https://developers.google.com/safe-browsing/v4/get-started
const SAFE_BROWSING_API_KEY = process.env.SAFE_BROWSING_API_KEY || ''; // <-- Paste your Google Safe Browsing API key here

async function checkWithGoogleSafeBrowsing(url) {
    // If no API key is configured, return null to signal fallback to ML
    if (!SAFE_BROWSING_API_KEY) return null;

    const endpoint = `https://safebrowsing.googleapis.com/v4/threatMatches:find?key=${SAFE_BROWSING_API_KEY}`;
    const body = {
        client: { clientId: 'digital-chaff-generator', clientVersion: '1.0' },
        threatInfo: {
            threatTypes: ['MALWARE', 'SOCIAL_ENGINEERING', 'UNWANTED_SOFTWARE', 'POTENTIALLY_HARMFUL_APPLICATION'],
            platformTypes: ['ANY_PLATFORM'],
            threatEntryTypes: ['URL'],
            threatEntries: [{ url }]
        }
    };

    try {
        const resp = await fetch(endpoint, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body)
        });
        if (!resp.ok) return null; // API error — fall through to ML
        const data = await resp.json();
        if (data.matches && data.matches.length > 0) {
            const threat = data.matches[0].threatType;
            return { risk: 'HIGH', reason: `Google Safe Browsing: ${threat}`, source: 'google' };
        }
        return { risk: 'LOW', reason: 'Google Safe Browsing: No threat found', source: 'google' };
    } catch (err) {
        console.warn('[DCG] Safe Browsing API error:', err.message);
        return null; // Network failure — fall through to ML
    }
}

async function checkUrl(url, tabId) {
    let risk = 'UNKNOWN';
    let reason = '';
    let googleResult = null;

    // ── Skip non-HTTP(S) browser-internal URLs immediately ───────────────────
    // chrome://, about:, file://, moz-extension://, newtab etc. are never phishing.
    if (!url || /^(chrome|chrome-extension|moz-extension|about|file|edge|brave|data):/i.test(url) || url === 'newtab' || url.startsWith('chrome://')) {
        const result = { url: url || 'newtab', risk: 'LOW', reason: 'Browser internal URL', score: 0.0 };
        saveToHistory(result);
        return result;
    }

    // ── Hard allowlist override ──────────────────────────────────────────────
    // Trusted domains always get LOW risk — no ML or heuristic can override this.
    if (isLegitDomain(url)) {
        const result = { url, risk: 'LOW', reason: 'Trusted domain (allowlist)', score: 0.0 };
        saveToHistory(result);
        return result;
    }

    // Always run our ML check
    const mlResult = checkWithPrivacyMode(url);

    // ── Thresholds (tuned to reduce false-negatives on short phishing domains)
    let mlRisk;
    if (mlResult.score >= 0.62) mlRisk = 'HIGH';
    else if (mlResult.score >= 0.42) mlRisk = 'MEDIUM';
    else mlRisk = 'LOW';

    // ── Heuristic escalation: short phishing domains (e.g. bank-update.click)
    // often score low because URL length pulls the RF toward benign. Override
    // when we see strong structural signals even if the score is below threshold.
    if (mlRisk === 'LOW') {
        try {
            const feats = extractFeatures(url);
            // Updated indices to match new 25-feature schema
            const suspTld = feats[9];   // index 9 = suspicious_tld
            const kwHost = feats[8];   // index 8 = keyword_in_hostname (NOT query)
            const kwPath = feats[22];  // index 22 = path_keyword_count
            const brandImp = feats[12];  // index 12 = brand_impersonation
            const hasHyphen = feats[6] >= 1 ? 1 : 0;
            const kwCount = kwHost + kwPath;  // combined keyword signal

            // Score: 1pt each for suspicious_tld, brand_impersonation, hyphen;
            // 1pt for every 2 phishing keywords found in hostname or path
            const hScore = suspTld + brandImp + hasHyphen + Math.floor(kwCount / 2);
            const isLegit = isLegitDomain(url);

            if (!isLegit && hScore >= 3) {
                mlRisk = 'HIGH';
                mlResult.reason = `Heuristic override: suspicious_tld=${suspTld}, brand_impersonation=${brandImp}, keywords=${kwCount}`;
            } else if (!isLegit && hScore >= 2) {
                mlRisk = 'MEDIUM';
                mlResult.reason = `Heuristic escalation: suspicious_tld=${suspTld}, brand_impersonation=${brandImp}, keywords=${kwCount}`;
            }
        } catch { /* ignore */ }
    }

    if (currentMode === 'privacy') {
        // ── Local ML only — no external calls ──────────────────────────────
        risk = mlRisk;
        reason = mlResult.reason;
    } else {
        // ── Accurate mode: Google Safe Browsing + ML dual check ─────────────
        googleResult = await checkWithGoogleSafeBrowsing(url);

        if (googleResult) {
            // Google API responded — it is authoritative
            risk = googleResult.risk;
            reason = googleResult.reason;

            // If Google says LOW but ML says HIGH, escalate to MEDIUM as a warning
            if (risk === 'LOW' && mlRisk === 'HIGH') {
                risk = 'MEDIUM';
                reason = 'Google: Safe | ML: suspicious — double-check recommended';
            }
        } else {
            // No API key or network error — fall back to ML with a note
            risk = mlRisk;
            reason = mlResult.reason + ' (Google API unavailable — add API key for full protection)';
        }
    }

    // Store both results so the popup can display them separately
    const combinedResult = {
        risk,
        reason,
        url,
        mlRisk,
        mlReason: mlResult.reason,
        googleRisk: googleResult ? googleResult.risk : null,
        googleReason: googleResult ? googleResult.reason : null
    };

    if (risk === 'HIGH' || risk === 'MEDIUM') {
        showPhishingWarning(url, risk, reason, tabId, combinedResult);
    }

    // ── Persist to URL detection history ────────────────────────────────────
    saveToHistory(combinedResult);

    return combinedResult;
}

/** Saves a URL check result to the history list (max 50 entries). */
function saveToHistory(result) {
    chrome.storage.local.get('urlHistory', (data) => {
        const history = data.urlHistory || [];
        const entry = {
            url: result.url,
            risk: result.risk,
            reason: result.reason,
            mlRisk: result.mlRisk,
            googleRisk: result.googleRisk,
            ts: Date.now()
        };
        // Prepend newest and trim to 50
        const updated = [entry, ...history].slice(0, 50);
        chrome.storage.local.set({ urlHistory: updated });
    });
}

