/** Returns true if the URL belongs to a known-safe domain. */
function isLegitDomain(url) {
    try {
        const hostname = new URL(url).hostname.toLowerCase();

        // 1. Exact match (e.g. already stored as 'dominos.co.in')
        if (LEGIT_DOMAIN_ALLOWLIST.has(hostname)) return true;

        const parts = hostname.split('.');

        // 2. Check last-3-parts first — handles .co.in, .co.uk, .com.au, .net.in etc.
        //    e.g. m.dominos.co.in → dominos.co.in
        if (parts.length >= 3) {
            const base3 = parts.slice(-3).join('.');
            if (LEGIT_DOMAIN_ALLOWLIST.has(base3)) return true;
        }

        // 3. Check last-2-parts — handles standard .com, .org, .net etc.
        //    e.g. www.paypal.com → paypal.com
        if (parts.length >= 2) {
            const base2 = parts.slice(-2).join('.');
            if (LEGIT_DOMAIN_ALLOWLIST.has(base2)) return true;
        }

        // 4. Trusted TLDs — any government / education / military domain worldwide
        const trustedPatterns = [
            /\.gov(\.[a-z]{2,3})?$/i,   // .gov, .gov.in, .gov.uk, .gov.au ...
            /\.edu(\.[a-z]{2,3})?$/i,   // .edu, .edu.in, .edu.au ...
            /\.mil(\.[a-z]{2,3})?$/i,   // .mil
            /\.ac\.[a-z]{2,3}$/i,       // .ac.uk, .ac.in, .ac.jp ...
            /\.nic\.[a-z]{2,3}$/i,      // .nic.in
            /\.go\.[a-z]{2,3}$/i,       // .go.jp, .go.kr
        ];
        if (trustedPatterns.some(p => p.test(hostname))) return true;
    } catch { /* ignore */ }
    return false;
}

// ── Known phishing brands (for impersonation detection) ──────────────────────
const PHISHING_BRANDS = [
    'paypal', 'apple', 'google', 'amazon', 'microsoft', 'facebook', 'instagram',
    'netflix', 'twitter', 'linkedin', 'dropbox', 'ebay', 'bankofamerica', 'chase',
    'wellsfargo', 'citibank', 'hsbc', 'barclays', 'dhl', 'fedex', 'ups', 'usps',
    'irs', 'whatsapp', 'telegram', 'yahoo', 'outlook', 'office365', 'steam',
    'coinbase', 'binance', 'blockchain', 'kraken', 'metamask',
];

const SUSPICIOUS_TLDS_JS = [
    '.top', '.xyz', '.click', '.ru', '.tk', '.ml', '.ga', '.cf', '.gq',
    '.pw', '.cc', '.biz', '.info', '.online', '.site', '.website', '.space',
    '.icu', '.live', '.fun', '.world', '.press', '.today', '.win', '.loan',
    '.vip', '.work', '.host', '.store',
];

// ── Phishing keywords: only checked in HOSTNAME and PATH, never query string ──
// This prevents false positives from ad tracking params like ?keyword=geeksforgeeks
const PHISHING_KEYWORDS_JS = [
    'login', 'signin', 'verify', 'secure', 'bank', 'update', 'account',
    'confirm', 'password', 'credential', 'billing', 'suspended', 'unusual',
    'authenticate', 'authorize', 'alert', 'warning', 'limited', 'expire',
    'recover', 'unlock', 'reset', 'validate', 'identity',
];

const URL_SHORTENERS_JS = new Set([
    'bit.ly', 'tinyurl.com', 'goo.gl', 't.co', 'ow.ly', 'buff.ly',
    'short.link', 'tiny.cc', 'is.gd', 'cli.gs',
]);

const SUSPICIOUS_FILE_EXTS = ['.exe', '.php', '.bat', '.sh', '.vbs', '.zip', '.rar', '.jar'];

/**
 * Extracts 25 features from a URL — must stay in EXACT sync with
 * extract_features() in train_models.py.
 *
 * KEY FIX (features 9 & 23): phishing keywords are counted ONLY in the
 * hostname and path — never in the query string. This eliminates false
 * positives from ad-tracking URLs (e.g. ?keyword=geeksforgeeks).
 */
function extractFeatures(url) {
    let hostname = '', path = '', query = '', scheme = 'https';
    let port = null;
    try {
        const u = new URL(url);
        hostname = (u.hostname || '').toLowerCase();
        path = u.pathname || '';
        query = u.search ? u.search.slice(1) : '';
        scheme = (u.protocol || 'https:').replace(':', '').toLowerCase();
        port = u.port ? parseInt(u.port, 10) : null;
    } catch {
        const m = url.match(/:\/\/(.[^/]+)/);
        hostname = m ? m[1].toLowerCase() : '';
    }

    const lhost = hostname.toLowerCase();
    const lpath = path.toLowerCase();
    const parts = lhost.split('.');

    // Base domain — check 3 parts first (.co.in, .co.uk, .com.au), then 2 parts (.com, .org)
    const baseDomain3 = parts.length >= 3 ? parts.slice(-3).join('.') : null;
    const baseDomain2 = parts.length >= 2 ? parts.slice(-2).join('.') : lhost;
    // For shortener/allowlist lookups: prefer the more-specific 3-part form if it's in the list
    const baseDomain = (baseDomain3 && (
        LEGIT_DOMAIN_ALLOWLIST.has(baseDomain3) ||
        URL_SHORTENERS_JS.has(baseDomain3)
    )) ? baseDomain3 : baseDomain2;

    // Helper: returns true if the hostname (or any of its base domains) is in the allowlist
    const isLegitCheck = (host) =>
        LEGIT_DOMAIN_ALLOWLIST.has(host) ||
        (baseDomain3 && LEGIT_DOMAIN_ALLOWLIST.has(baseDomain3)) ||
        LEGIT_DOMAIN_ALLOWLIST.has(baseDomain2);

    // F7: hyphens in HOSTNAME only
    const f7 = (lhost.match(/-/g) || []).length;

    // F8: digit ratio across full URL
    const digits = (url.match(/\d/g) || []).length;
    const f8 = url.length > 0 ? digits / url.length : 0;

    // F9: phishing keywords in HOSTNAME only (not query!)
    const f9 = PHISHING_KEYWORDS_JS.reduce(
        (acc, kw) => acc + (lhost.split(kw).length - 1), 0);

    // F13: brand impersonation — brand in URL but not a real domain
    const isLegit = isLegitCheck(lhost);
    const brandInHost = PHISHING_BRANDS.some(b => lhost.includes(b));
    const f13 = (brandInHost && !isLegit) ? 1 : 0;

    // F14: redirect keywords in PATH only (not query)
    const redirectKws = ['redirect', 'return', 'next', 'goto', 'target', 'redir'];
    const f14 = redirectKws.some(k => lpath.includes(k)) ? 1 : 0;

    // F20: hyphens × hostname keywords
    const f20 = f7 * f9;

    // F21: non-standard port
    const f21 = (port && port !== 80 && port !== 443 && port !== 8080 && port !== 8443) ? 1 : 0;

    // F22: URL shortener
    const f22 = URL_SHORTENERS_JS.has(baseDomain) ? 1 : 0;

    // F23: phishing keywords in PATH only
    const f23 = PHISHING_KEYWORDS_JS.reduce(
        (acc, kw) => acc + (lpath.split(kw).length - 1), 0);

    // F24: number of query parameters
    const f24 = query ? query.split('&').filter(p => p.includes('=')).length : 0;

    // F25: suspicious file extension in path
    const pathLower = lpath.replace(/\/$/, '');
    const f25 = SUSPICIOUS_FILE_EXTS.some(ext => pathLower.endsWith(ext)) ? 1 : 0;

    return [
        url.length,                                                                  //  0 url_length
        hostname.length,                                                             //  1 hostname_length
        (url.match(/\./g) || []).length,                                             //  2 dot_count
        (path.match(/\//g) || []).length,                                            //  3 slash_count
        Math.max(0, (lhost.match(/\./g) || []).length - 1),                          //  4 subdomain_depth
        url.includes('@') ? 1 : 0,                                                   //  5 has_at
        f7,                                                                          //  6 hyphen_count_hostname
        f8,                                                                          //  7 digit_ratio
        f9,                                                                          //  8 keyword_in_hostname
        SUSPICIOUS_TLDS_JS.some(t => lhost.endsWith(t)) ? 1 : 0,                    //  9 suspicious_tld
        calculateEntropy(url),                                                       // 10 url_entropy
        scheme === 'http' ? 1 : 0,                                                   // 11 is_http
        f13,                                                                         // 12 brand_impersonation
        f14,                                                                         // 13 redirect_in_path
        path.length,                                                                 // 14 path_length
        query.length,                                                                // 15 query_length
        ['%', '&', '=', '+', '#', ';', '!'].reduce(
            (acc, c) => acc + (url.split(c).length - 1), 0),                        // 16 special_char_count
        /^\d{1,3}(\.\d{1,3}){3}$/.test(hostname) ? 1 : 0,                          // 17 is_ip_address
        ['.gov', '.edu', '.mil', '.ac.uk', '.ac.in'].some(
            t => lhost.endsWith(t)) ? 1 : 0,                                         // 18 trusted_tld
        f20,                                                                         // 19 hyphen_x_hostname_keywords
        f21,                                                                         // 20 has_nonstandard_port
        f22,                                                                         // 21 is_url_shortener
        f23,                                                                         // 22 path_keyword_count
        f24,                                                                         // 23 query_param_count
        f25,                                                                         // 24 suspicious_file_ext
        // F26: Known-legit domain flag — mirrors Python LEGIT_DOMAINS set
        isLegitCheck(lhost) ? 1 : 0,                                                // 25 is_legit_domain
    ];
}

/** Traverses a single decision-tree node (works for RF and GBM sklearn trees). */
function traverseSklearnNode(node, features) {
    let current = node;
    while (true) {
        if (current.feature === -2) {
            // Leaf: value = [benign_prob, phishing_prob]
            return current.value[1];
        }
        current = features[current.feature] <= current.threshold
            ? current.left
            : current.right;
    }
}

/** Traverses a single XGBoost tree node. Returns log-odds contribution. */
function traverseXGBNode(node, features) {
    if (node.feature === -2) return node.leaf;  // leaf: log-odds
    return features[node.feature] < node.threshold
        ? traverseXGBNode(node.left, features)
        : traverseXGBNode(node.right, features);
}

/** Runs ML inference — handles both sklearn (RF/GBM) and XGBoost models. */
function runMLInference(features) {
    const family = ML_MODEL.model_family || 'sklearn_rf';

    if (family === 'xgboost') {
        // XGBoost: sum leaf log-odds across all trees, then apply sigmoid
        const baseScore = ML_MODEL.base_score || 0.5;
        const logit = ML_MODEL.trees.reduce(
            (sum, tree) => sum + traverseXGBNode(tree, features),
            Math.log(baseScore / (1 - baseScore))
        );
        return 1 / (1 + Math.exp(-logit));
    }

    // sklearn (RandomForest, GradientBoosting, DecisionTree): average class probs
    const total = ML_MODEL.trees.reduce(
        (sum, tree) => sum + traverseSklearnNode(tree, features), 0
    );
    return total / ML_MODEL.n_trees;
}

/** Performs local ML analysis without external API calls. */
function checkWithPrivacyMode(url) {
    try {
        // Hard override: known-legitimate domains are always LOW risk
        if (isLegitDomain(url)) {
            return {
                score: 0.05,
                reason: 'Verified legitimate domain — always safe'
            };
        }

        const features = extractFeatures(url);
        const score = runMLInference(features);
        const conf = Math.round(score * 100);

        return {
            score,
            reason: `Local ML: ${conf}% phishing match`
        };
    } catch (err) {
        console.warn('[DCG] ML inference error:', err?.message || err);
        // Default to LOW risk on crash — better to miss a threat than
        // to falsely flag a safe site like pizzahut.co.in as dangerous.
        return { score: 0.15, reason: 'ML unavailable — defaulting safe' };
    }
}

// ── Warning broadcast ─────────────────────────────────────────────────────────
function showPhishingWarning(url, risk, reason, tabId, combinedResult) {
    console.warn(`[DCG] ⚠️  Phishing Warning — ${url}`);
    console.warn(`[DCG] Risk: ${risk} | ${reason}`);

    // 1. Broadcast to popup (include full dual-auth data)
    chrome.runtime.sendMessage({
        type: 'PHISHING_ALERT', url, risk, reason,
        mlRisk: combinedResult?.mlRisk ?? null,
        mlReason: combinedResult?.mlReason ?? null,
        googleRisk: combinedResult?.googleRisk ?? null,
        googleReason: combinedResult?.googleReason ?? null
    }).catch(() => { /* popup not open — that's fine */ });

    // 2. Persist to storage
    chrome.storage.local.set({
        lastPhishingAlert: { url, risk, reason, ts: Date.now() }
    });

    // 3. If HIGH risk, inject the warning overlay into the page itself
    if (risk === 'HIGH' && tabId) {
        injectWarning(tabId, url, reason);
    }
}

/** Injects the premium warning overlay into the target tab. */
async function injectWarning(tabId, url, reason) {
    try {
        console.log(`[DCG Phishing] Injecting warning overlay into tab ${tabId}`);
        await chrome.scripting.executeScript({
            target: { tabId },
            func: showWarningOverlay,
            args: [url, reason]
        });
    } catch (err) {
        console.error('[DCG Phishing] Failed to inject warning overlay:', err);
    }
}

// ── Tab listener ──────────────────────────────────────────────────────────────

/** Returns true only if the tab still exists at call time. */
async function tabExists(tabId) {
    try {
        await chrome.tabs.get(tabId);
        return true;
    } catch {
        return false;
    }
}

function registerTabListener() {
    // URL change — check after the async API call whether tab is still open
    chrome.tabs.onUpdated.addListener(async (tabId, changeInfo) => {
        if (!changeInfo.url) return;

        const result = await checkUrl(changeInfo.url, tabId);
        if (!result) return;

        // Tab may have closed while Safe Browsing was running — bail out silently
        if (!(await tabExists(tabId))) return;

        // Cache result
        const { tabRiskCache = {} } = await chrome.storage.local.get('tabRiskCache');
        tabRiskCache[tabId] = { url: changeInfo.url, ...result, ts: Date.now() };
        chrome.storage.local.set({ tabRiskCache });

        updateBadge(result.risk, tabId);
    });

    // Clean up cache when tab closes — do NOT touch the badge (tab is gone)
    chrome.tabs.onRemoved.addListener((tabId) => {
        chrome.storage.local.get('tabRiskCache', ({ tabRiskCache }) => {
            if (!tabRiskCache) return;
            delete tabRiskCache[tabId];
            chrome.storage.local.set({ tabRiskCache });
        });
    });

    // When user switches to a tab, restore that tab's badge
    chrome.tabs.onActivated.addListener(async ({ tabId }) => {
        if (!(await tabExists(tabId))) return;
        const { tabRiskCache } = await chrome.storage.local.get('tabRiskCache');
        const entry = tabRiskCache?.[tabId];
        if (entry) updateBadge(entry.risk, tabId);
        else clearBadge(tabId);
    });

    console.log('[DCG Phishing] Tab listeners registered.');
}

// ── Public API ────────────────────────────────────────────────────────────────
export const PhishingDetector = {
    /** Call once from background.js at startup. */
    init() {
        initSettings();
        registerTabListener();
        console.log('[DCG Phishing] Detector initialised.');
    },

    /** Called by background.js message handler so popup can request a live check. */
    checkUrl
};
